module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
); 
    integer i;
    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    reg [4:0] i_r;
    reg done_r;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i_r <= 0;
        end
        else begin
            if(start && i_r < 17) begin
                i_r <= i_r + 1;
            end
            else begin
                i_r <= 0;
            end
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 0;
        end
        else begin
            if(i_r == 16) begin
                done_r <= 1;
            end
            else if(i_r == 17) begin
                done_r <= 0;
            end
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end
        else begin
            if(start) begin
                if(i_r == 0) begin
                    areg <= ain;
                    breg <= bin;
                end
                else if(i_r > 0 && i_r < 17) begin
                    if(areg[i_r-1]) begin
                        yout_r <= yout_r + (breg << (i_r-1));
                    end
                end
            end
        end
    end

    assign yout = yout_r;
    assign done = done_r;
endmodule
